import{_ as a,a as i,a3 as t,o as s}from"./chunks/framework.edeurCMZ.js";const u=JSON.parse('{"title":"Configuring Field Translation in HPCC Platform","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/userdoc/FieldTranslation.md","filePath":"devdoc/userdoc/FieldTranslation.md","lastUpdated":1782747484000}'),l={name:"devdoc/userdoc/FieldTranslation.md"};function n(o,e,r,d,h,c){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="configuring-field-translation-in-hpcc-platform" tabindex="-1">Configuring Field Translation in HPCC Platform <a class="header-anchor" href="#configuring-field-translation-in-hpcc-platform" aria-label="Permalink to &quot;Configuring Field Translation in HPCC Platform&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Field translation controls what happens when the ECL record layout in a query does not match the ECL record layout that was used when the file was published to the Distributed File System (DFS). This document explains the available configuration levels, the valid values, and their precedence.</p><h2 id="configuration-levels" tabindex="-1">Configuration Levels <a class="header-anchor" href="#configuration-levels" aria-label="Permalink to &quot;Configuration Levels&quot;">​</a></h2><p>Field translation can be configured at three levels, listed from highest to lowest precedence:</p><ol><li><strong>Activity level</strong> — applies to a single DATASET or INDEX read.</li><li><strong>Query level</strong> — applies to all reads within a single ECL query.</li><li><strong>Global level</strong> — applies platform-wide as a default for all queries.</li></ol><h3 id="activity-level" tabindex="-1">Activity Level <a class="header-anchor" href="#activity-level" aria-label="Permalink to &quot;Activity Level&quot;">​</a></h3><p>Use a <code>HINT</code> on the DATASET or INDEX declaration:</p><div class="language-ecl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ecl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">myDs :</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DATASET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;~scope::myfile&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, RecStruct, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">THOR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, HINT(layoutTranslation(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)));</span></span></code></pre></div><p>See <a href="#valid-values">Valid Values</a> for the accepted <code>&lt;value&gt;</code> options.</p><h3 id="query-level" tabindex="-1">Query Level <a class="header-anchor" href="#query-level" aria-label="Permalink to &quot;Query Level&quot;">​</a></h3><p>Use <code>#OPTION</code> at the top of the ECL query:</p><div class="language-ecl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ecl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#OPTION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layoutTranslation&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>See <a href="#valid-values">Valid Values</a> for the accepted <code>&lt;value&gt;</code> options.</p><h3 id="global-level" tabindex="-1">Global Level <a class="header-anchor" href="#global-level" aria-label="Permalink to &quot;Global Level&quot;">​</a></h3><p>Set the <code>fieldTranslationEnabled</code> attribute in the environment.xml or Helm chart for each engine that requires it. Because there is no single global setting that covers all engines, it must be set independently for each one:</p><ul><li><strong>Thor</strong>: add <code>fieldTranslationEnabled</code> as an attribute under <code>ThorCluster</code>.</li><li><strong>hThor</strong>: add <code>fieldTranslationEnabled</code> under the hThor definition.</li><li><strong>Roxie</strong>: add <code>fieldTranslationEnabled</code> under the Roxie definition.</li></ul><h2 id="valid-values" tabindex="-1">Valid Values <a class="header-anchor" href="#valid-values" aria-label="Permalink to &quot;Valid Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Value</th><th>Behaviour</th></tr></thead><tbody><tr><td><em>(unset)</em> | <code>&quot;on&quot;</code> | <code>&quot;true&quot;</code> | <code>&quot;yes&quot;</code> | <code>&quot;1&quot;</code> | <code>&quot;payload&quot;</code></td><td><strong>Translate where possible.</strong> Key fields of indexes cannot be translated. This is the default.</td></tr><tr><td><code>&quot;false&quot;</code> | <code>&quot;no&quot;</code> | <code>&quot;0&quot;</code> | <em>(any other non-blank value, e.g., <code>&quot;off&quot;</code>)</em></td><td><strong>No translation.</strong> If the published layout and the query layout differ, an error is thrown and the query is aborted.</td></tr><tr><td><code>&quot;alwaysECL&quot;</code> | <code>&quot;ecl&quot;</code></td><td><strong>Force the query&#39;s ECL definition.</strong> The published layout is ignored entirely. Use only in special cases where the ECL definition is known to be authoritative (e.g., reading a fixed-length CSV sprayed as lines with a known fixed-field overlay). Incorrect use will very likely crash queries. Since 7.12.20, using <code>&quot;alwaysECL&quot;</code> at query or global level issues a warning and the option is ignored — the system behaves as if translation is off. See <a href="https://github.com/hpcc-systems/HPCC-Platform/pull/14461" target="_blank" rel="noreferrer">PR #14461</a>.</td></tr><tr><td><code>&quot;alwaysDisk&quot;</code> | <code>&quot;disk&quot;</code></td><td><strong>Developer option only.</strong> Forces translation <em>on</em> for ECL flat-disk read statements that attempt to read non-flat files. Normally translation is off in this scenario.</td></tr></tbody></table><h2 id="precedence" tabindex="-1">Precedence <a class="header-anchor" href="#precedence" aria-label="Permalink to &quot;Precedence&quot;">​</a></h2><p>Activity level (HINT) &gt; Query level (#OPTION) &gt; Global level (environment.XML or Helm chart).</p><h2 id="disabling-field-translation-globally" tabindex="-1">Disabling Field Translation Globally <a class="header-anchor" href="#disabling-field-translation-globally" aria-label="Permalink to &quot;Disabling Field Translation Globally&quot;">​</a></h2><h3 id="bare-metal" tabindex="-1">Bare Metal <a class="header-anchor" href="#bare-metal" aria-label="Permalink to &quot;Bare Metal&quot;">​</a></h3><p>To turn off field translation as the default for all queries, set <code>fieldTranslationEnabled</code> to <code>&quot;off&quot;</code> (or any non-blank, non-affirmative value) in the <code>ThorCluster</code>, hThor, and Roxie sections of the environment.xml.</p><p>Individual queries or activities can still override this with a <code>#OPTION</code> or <code>HINT</code> if selective translation is needed.</p><h3 id="containerized" tabindex="-1">Containerized <a class="header-anchor" href="#containerized" aria-label="Permalink to &quot;Containerized&quot;">​</a></h3><p>In a containerized deployment, you can turn off field translation as the default for all queries, by setting <code>fieldTranslationEnabled</code> to <code>&quot;false&quot;</code> in each engine&#39;s section in the override Helm chart.</p><p>For example:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">thor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">thor</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    prefix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">thor</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    numWorkers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    maxJobs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    maxGraphs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    fieldTranslationEnabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;false&quot;</span></span></code></pre></div>`,29)])])}const k=a(l,[["render",n]]);export{u as __pageData,k as default};
